class Solution:
    def integerReplacement(self, n):
        from functools import lru_cache
        import sys
        sys.setrecursionlimit(10000)
        @lru_cache(maxsize=None)
        def steps(x):
            if x == 1:
                return 0
            if x % 2 == 0:
                return 1 + steps(x // 2)
            return 1 + min(steps(x + 1), steps(x - 1))
        return steps(n)

